// ─── UTILITÁRIOS ─────────────────────────────────────────────────────────────
function today() {
  const d=new Date();
  return `${String(d.getDate()).padStart(2,"0")}.${String(d.getMonth()+1).padStart(2,"0")}.${d.getFullYear()}`;
}

// Lê imagem diretamente como base64 — sem Canvas, funciona em qualquer ambiente
function readImageB64(file) {
  return new Promise((res, rej) => {
    const reader = new FileReader();
    reader.onload = () => {
      const dataUrl = reader.result;
      const b64 = dataUrl.split(",")[1];
      const img = new Image();
      img.onload = () => res({ b64, w: img.naturalWidth||800, h: img.naturalHeight||600, name: file.name, type: file.type });
      img.onerror  = () => res({ b64, w: 800, h: 600, name: file.name, type: file.type });
      img.src = dataUrl;
    };
    reader.onerror = rej;
    reader.readAsDataURL(file);
  });
}

