// ─── MINI UPLOAD (usado dentro do FotoCard para cada imagem) ─────────────────
function MiniUpload({foto, onFoto, onRemove, label}) {
  const [drag,setDrag]=useState(false);
  const [loading,setLoading]=useState(false);
  const ref=useRef();
  const process=async(files)=>{
    const f=Array.from(files).find(f=>f.type.startsWith("image/"));
    if(!f) return;
    setLoading(true);
    try { onFoto(await readImageB64(f)); } catch(e){console.error(e);}
    setLoading(false);
  };
  return (
    <div style={{flex:1,minWidth:0,border:`1px solid ${foto?C.borderLight:C.border}`,
      borderRadius:6,overflow:"hidden",transition:"border-color .2s",background:foto?"#000":C.surface}}>
      {/* mini toolbar */}
      {foto&&(
        <div style={{display:"flex",gap:4,padding:"4px 8px",background:C.navy,
          justifyContent:"flex-end"}}>
          <button onClick={()=>ref.current?.click()}
            style={{background:"none",border:`1px solid ${C.border}`,color:C.muted,
              borderRadius:3,padding:"1px 7px",cursor:"pointer",fontSize:10}}>Trocar</button>
          <button onClick={onRemove}
            style={{background:"none",border:"none",color:C.danger,cursor:"pointer",
              fontSize:12,fontWeight:700}}>✕</button>
        </div>
      )}
      {/* drop zone */}
      <div
        onDrop={e=>{e.preventDefault();e.stopPropagation();setDrag(false);process(e.dataTransfer.files);}}
        onDragOver={e=>{e.preventDefault();e.stopPropagation();setDrag(true);}}
        onDragEnter={e=>{e.preventDefault();e.stopPropagation();setDrag(true);}}
        onDragLeave={e=>{e.preventDefault();setDrag(false);}}
        onClick={()=>{ if(!foto&&!loading) ref.current?.click(); }}
        style={{background:drag?"rgba(59,130,246,0.18)":foto?"#000":C.surface,
          minHeight:foto?0:90,cursor:foto?"default":"pointer",
          display:"flex",alignItems:"center",justifyContent:"center",
          flexDirection:"column",border:drag?`2px dashed ${C.accent}`:"2px solid transparent"}}>
        <input ref={ref} type="file" accept="image/*" style={{display:"none"}}
          onChange={e=>{process(e.target.files);e.target.value="";}}/>
        {loading?(
          <div style={{textAlign:"center",padding:10}}>
            <div style={{width:22,height:22,border:`3px solid ${C.accent}44`,borderTopColor:C.accent,
              borderRadius:"50%",animation:"spin .7s linear infinite",margin:"0 auto 6px"}}/>
            <div style={{color:C.muted,fontSize:10}}>Carregando...</div>
          </div>
        ):foto?(
          <img src={`data:${foto.type||"image/jpeg"};base64,${foto.b64}`} alt=""
            style={{width:"100%",maxHeight:200,objectFit:"contain",display:"block"}}/>
        ):(
          <div style={{textAlign:"center",padding:16,pointerEvents:"none"}}>
            <div style={{fontSize:26,marginBottom:6}}>📷</div>
            <div style={{color:C.muted,fontSize:11,marginBottom:8}}>{label}</div>
            <div style={{background:C.accent,color:"#fff",borderRadius:6,
              padding:"5px 14px",display:"inline-block",fontSize:11,fontWeight:700}}>
              Escolher
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── FOTO CARD ─── suporta até 6 imagens em grid + comentário compartilhado
const FOTO_LABELS=["Foto 1","Foto 2","Foto 3","Foto 4","Foto 5","Foto 6"];
function FotoCard({n,fotos,comentario,onFoto,onRemove,onComentario}) {
  const temFoto = fotos.some(f=>!!f);
  return (
    <div style={{background:C.card,border:`1px solid ${temFoto?C.borderLight:C.border}`,
      borderRadius:12,overflow:"hidden",transition:"border-color .2s",
      boxShadow:temFoto?`0 0 0 1px ${C.accent}22`:"none"}}>
      {/* Header */}
      <div style={{background:C.navy,padding:"8px 14px",display:"flex",
        alignItems:"center",justifyContent:"space-between"}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{background:C.accent,color:"#fff",borderRadius:4,width:20,height:20,
            display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700}}>{n}</div>
          <span style={{color:"#cbd5e1",fontSize:12,fontWeight:700,letterSpacing:.5}}>
            REGISTRO FOTOGRÁFICO {String(n).padStart(2,"0")}
          </span>
        </div>
      </div>
      {/* Grid de fotos (3 colunas x 2 linhas) */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:4,padding:4,background:C.surface}}>
        {fotos.map((foto,fi)=>(
          <MiniUpload key={fi} foto={foto} onFoto={v=>onFoto(fi,v)} onRemove={()=>onRemove(fi)}
            label={FOTO_LABELS[fi]}/>
        ))}
      </div>
      {/* Comentário compartilhado */}
      <div style={{padding:"8px 12px"}}>
        <div style={{fontSize:10,fontWeight:700,letterSpacing:.6,color:C.muted,
          textTransform:"uppercase",marginBottom:4}}>Comentários:</div>
        <textarea value={comentario} onChange={e=>onComentario(e.target.value)}
          placeholder="Descreva o que está visível nestas fotos..."
          rows={2}
          style={{width:"100%",background:C.surface,border:`1px solid ${C.border}`,
            borderRadius:7,color:C.text,padding:"8px 10px",fontSize:12,
            fontFamily:"inherit",outline:"none",resize:"vertical",boxSizing:"border-box"}}
          onFocus={e=>e.target.style.borderColor=C.accent}
          onBlur={e=>e.target.style.borderColor=C.border}
        />
      </div>
    </div>
  );
}


